 49	  if (processSurface.error?.code === 'PROJECT_FORBIDDEN') {
 50	    container.append(renderForbiddenProcessState(args.targetDocument));
 51	    return container;
 52	  }
 53	
 54	  if (processSurface.error?.code === 'PROJECT_NOT_FOUND') {
 55	    container.append(renderMissingProjectState(args.targetDocument));
 56	    return container;
 57	  }
 58	
 59	  if (processSurface.error?.code === 'PROCESS_NOT_FOUND') {
 60	    container.append(renderMissingProcessState(args.targetDocument));
 61	    return container;
 62	  }
 63	
 64	  if (
 65	    processSurface.error !== null ||
 66	    processSurface.project === null ||
 67	    processSurface.process === null
 68	  ) {
 69	    const error = args.targetDocument.createElement('section');
 70	    const title = args.targetDocument.createElement('h2');
 71	    const body = args.targetDocument.createElement('p');
 72	    title.textContent = 'Process work surface failed to load';
 73	    body.textContent = processSurface.error?.message ?? 'The process work surface is unavailable.';
 74	    error.append(title, body);
 75	    container.append(error);
 76	    return container;
 77	  }
 78	
 79	  const activeProject = processSurface.project;
 80	  const activeProcess = processSurface.process;
 81	
 82	  const backButton = args.targetDocument.createElement('button');
 83	  backButton.type = 'button';
 84	  backButton.textContent = 'Back to project';
 85	  backButton.addEventListener('click', () => {
 86	    args.onOpenProject(activeProject.projectId);
 87	  });
 88	
 89	  const projectHeading = args.targetDocument.createElement('h2');
 90	  const projectRole = args.targetDocument.createElement('p');
 91	  const processHeading = args.targetDocument.createElement('h3');
 92	  const processMeta = args.targetDocument.createElement('p');
 93	  const processPhase = args.targetDocument.createElement('p');
 94	
 95	  projectHeading.textContent = activeProject.name;
 96	  projectRole.textContent = `Role: ${activeProject.role}`;
 97	  processHeading.textContent = activeProcess.displayLabel;
 98	  processMeta.textContent = `${formatProcessTypeLabel(activeProcess.processType)} • ${formatProcessStatusLabel(activeProcess.status)}`;
 99	  processPhase.textContent = `Phase: ${activeProcess.phaseLabel}`;
100	  container.append(
101	    backButton,
102	    projectHeading,
103	    projectRole,
104	    processHeading,
105	    processMeta,
106	    processPhase,
107	  );
108	
109	  if (activeProcess.availableActions.includes('start')) {
110	    const startButton = args.targetDocument.createElement('button');
111	    startButton.type = 'button';
112	    startButton.textContent = 'Start process';
113	    startButton.addEventListener('click', () => {
114	      args.onStartProcess?.(activeProject.projectId, activeProcess.processId);
115	    });
116	    container.append(startButton);
117	  }
118	
119	  if (activeProcess.availableActions.includes('resume')) {
120	    const resumeButton = args.targetDocument.createElement('button');
121	    resumeButton.type = 'button';
122	    resumeButton.textContent = 'Resume process';
123	    resumeButton.addEventListener('click', () => {
124	      args.onResumeProcess?.(activeProject.projectId, activeProcess.processId);
125	    });
126	    container.append(resumeButton);
127	  }
128	
129	  if (processSurface.actionError !== null) {
130	    const actionError = args.targetDocument.createElement('p');
131	    actionError.setAttribute('data-process-action-error', 'true');
132	    actionError.setAttribute('role', 'alert');
133	    actionError.textContent = processSurface.actionError.message;
134	    container.append(actionError);
135	  }
136	
137	  if (activeProcess.nextActionLabel !== null) {
138	    const nextAction = args.targetDocument.createElement('p');
139	    nextAction.textContent = `Next action: ${activeProcess.nextActionLabel}`;
140	    container.append(nextAction);
141	  }
142	
143	  container.append(
144	    renderCurrentRequestPanel({
145	      currentRequest: processSurface.currentRequest,
146	      targetDocument: args.targetDocument,
147	    }),
148	    renderProcessHistorySection({
149	      envelope: processSurface.history,
150	      targetDocument: args.targetDocument,
151	    }),
152	    renderProcessMaterialsSection({
153	      envelope: processSurface.materials,
154	      targetDocument: args.targetDocument,
155	    }),
156	    renderSideWorkSection({
157	      envelope: processSurface.sideWork,
158	      targetDocument: args.targetDocument,
159	    }),
160	  );
161	
162	  return container;
163	}

