 34	function renderUnavailableShell(title: string, message: string): string {
 35	  return `<!doctype html>
 36	<html lang="en">
 37	  <head>
 38	    <meta charset="utf-8" />
 39	    <meta name="viewport" content="width=device-width, initial-scale=1" />
 40	    <title>${title}</title>
 41	  </head>
 42	  <body>
 43	    <main>
 44	      <h1>${title}</h1>
 45	      <p>${message}</p>
 46	    </main>
 47	  </body>
 48	</html>`;
