 51	export async function registerProcessRoutes(app: FastifyInstance): Promise<void> {
 52	  void processRoutePatterns;
 53	
 54	  const typedApp = app.withTypeProvider<ZodTypeProvider>();
 55	
 56	  typedApp.get(
 57	    '/projects/:projectId/processes/:processId',
 58	    {
 59	      schema: {
 60	        params: getProcessWorkSurfaceRouteSchema.params,
 61	        response: processHtmlRouteSchema.response,
 62	      },
 63	    },
 64	    async (request, reply) => {
 65	      if (request.actor === null) {
 66	        if (request.authFailureReason === 'invalid_session') {
 67	          reply.clearCookie(sessionCookieName, { path: '/' });
 68	        }
 69	
 70	        return reply.redirect(buildLoginRedirectPath(request.url));
 71	      }
 72	
 73	      const access = await app.processAccessService.getProcessAccess({
 74	        actor: request.actor,
 75	        projectId: request.params.projectId,
 76	        processId: request.params.processId,
 77	      });
 78	
 79	      if (access.kind === 'forbidden') {
 80	        return reply
 81	          .code(403)
 82	          .type('text/html')
 83	          .send(renderUnavailableShell('Access denied', 'You do not have access to this process.'));
 84	      }
 85	
 86	      if (access.kind === 'project_not_found') {
 87	        return reply
 88	          .code(404)
 89	          .type('text/html')
 90	          .send(
 91	            renderUnavailableShell(
 92	              'Project not found',
 93	              'The requested project could not be found.',
 94	            ),
 95	          );
 96	      }
 97	
 98	      if (access.kind === 'process_not_found') {
 99	        return reply
100	          .code(404)
101	          .type('text/html')
102	          .send(
103	            renderUnavailableShell(
104	              'Process unavailable',
105	              'The requested process could not be opened.',
106	            ),
107	          );
108	      }
109	
110	      const url = new URL(request.url, 'http://story2.local');
111	      const payload = buildShellBootstrapPayload({
112	        actor: {
113	          id: request.actor.userId,
114	          email: request.actor.email,
115	          displayName: request.actor.displayName,
116	        },
117	        pathname: `/projects/${request.params.projectId}/processes/${request.params.processId}`,
118	        search: url.search,
119	        csrfToken: reply.generateCsrf(),
120	      });
121	
122	      return reply.type('text/html').send(await app.renderShellDocument(payload, request.url));
123	    },
124	  );
125	
126	  typedApp.get(
127	    '/api/projects/:projectId/processes/:processId',
128	    {
129	      schema: getProcessWorkSurfaceRouteSchema,
130	    },
131	    async (request, reply) => {
132	      if (request.actor === null) {
133	        if (request.authFailureReason === 'invalid_session') {
134	          reply.clearCookie(sessionCookieName, { path: '/' });
135	        }
136	
137	        return reply.code(401).send({
138	          code: 'UNAUTHENTICATED',
139	          message: 'Authenticated access is required.',
140	          status: 401,
141	        });
142	      }
143	
144	      try {
145	        const surface = await app.processWorkSurfaceService.getSurface({
146	          actor: request.actor,
147	          projectId: request.params.projectId,
148	          processId: request.params.processId,
149	        });
150	
151	        return reply.code(200).send(surface);
152	      } catch (error) {
153	        if (error instanceof AppError) {
154	          const statusCode = error.statusCode as 403 | 404;
155	          const code = error.code as
156	            | 'PROJECT_FORBIDDEN'
157	            | 'PROJECT_NOT_FOUND'
158	            | 'PROCESS_NOT_FOUND';
159	
160	          return reply.code(statusCode).send({
161	            code,
162	            message: error.message,
163	            status: statusCode,
164	          });
165	        }
166	
167	        throw error;
168	      }
169	    },
170	  );
171	
172	  typedApp.post(
173	    '/api/projects/:projectId/processes/:processId/start',
174	    {
175	      schema: startProcessRouteSchema,
176	    },
177	    async (request, reply) => {
178	      if (request.actor === null) {
179	        if (request.authFailureReason === 'invalid_session') {
180	          reply.clearCookie(sessionCookieName, { path: '/' });
181	        }
182	
183	        return reply.code(401).send({
184	          code: 'UNAUTHENTICATED',
185	          message: 'Authenticated access is required.',
186	          status: 401,
187	        });
188	      }
189	
190	      try {
191	        const response = await app.processStartService.start({
192	          actor: request.actor,
193	          projectId: request.params.projectId,
194	          processId: request.params.processId,
195	        });
196	
197	        return reply.code(200).send(response);
198	      } catch (error) {
199	        if (error instanceof AppError) {
200	          const statusCode = error.statusCode as 403 | 404 | 409;
201	          const code = error.code as
202	            | 'PROJECT_FORBIDDEN'
203	            | 'PROJECT_NOT_FOUND'
204	            | 'PROCESS_NOT_FOUND'
205	            | 'PROCESS_ACTION_NOT_AVAILABLE';
206	
207	          return reply.code(statusCode).send({
