658	  private transitionProcessToRunning(processId: string): ProcessActionStoreResult {
659	    for (const [projectId, processes] of this.processesByProjectId.entries()) {
660	      const index = processes.findIndex((process) => process.processId === processId);
661	
662	      if (index === -1) {
663	        continue;
664	      }
665	
666	      const existing = processes[index];
667	
668	      if (existing === undefined) {
669	        continue;
670	      }
671	
672	      const now = new Date().toISOString();
673	      const nextProcess = processSummarySchema.parse({
674	        ...existing,
675	        status: 'running',
676	        phaseLabel: existing.phaseLabel === 'Draft' ? 'Working' : existing.phaseLabel,
677	        nextActionLabel: 'Monitor progress in the work surface',
678	        availableActions: ['open', 'review'],
679	        updatedAt: now,
680	      });
681	      const nextProcesses = [...processes];
682	      nextProcesses[index] = nextProcess;
683	      this.processesByProjectId.set(projectId, nextProcesses);
684	      this.currentRequestsByProcessId.set(processId, null);
685	      this.updateProjectSummary(projectId, (project) => ({
686	        ...project,
687	        lastUpdatedAt: now,
688	      }));
689	
690	      return {
691	        process: nextProcess,
692	        currentRequest: null,
693	      };
694	    }
695	
696	    const now = new Date().toISOString();
697	
698	    return {
699	      process: processSummarySchema.parse({
700	        processId,
701	        displayLabel: 'Unavailable process',
702	        processType: 'FeatureSpecification',
703	        status: 'running',
704	        phaseLabel: 'Working',
705	        nextActionLabel: 'Monitor progress in the work surface',
706	        availableActions: ['open', 'review'],
707	        hasEnvironment: false,
708	        updatedAt: now,
709	      }),
