 67	export function deriveProcessSurfaceAvailableActions(
 68	  status: ProcessSummary['status'],
 69	): ProcessSurfaceSummary['availableActions'] {
 70	  switch (status) {
 71	    case 'draft':
 72	      return ['start'];
 73	    case 'running':
 74	      return ['review'];
 75	    case 'waiting':
 76	      return ['respond'];
 77	    case 'paused':
 78	      return ['resume'];
 79	    case 'completed':
 80	      return ['review'];
 81	    case 'failed':
